// Script Continued Below
(function executeRule(current, previous /*null when async*/) {

		// RAJ STRY0011407 moved into the before Insert of Process Instance

// 	var recTaskInst = new GlideRecordSecure('x_153465_discovert_route_task_instance');
// 	recTaskInst.initialize();

// 	// RAJ - 2018-02-20 STRY0010829 - Short Desc and Instructions are missing in the Top Task . They need to be copied from the Process Definition.
// 	// had to change the line below to current.sys_id from recRunTemp.sys_id.  
// 	// The tasker instance insert is expecting the proces definition, not the process instance.


// 	// Set the Top Task on the Process Instance
//	var wf = new global.Workflow();
// 	var  wfId = wf.getWorkflowFromName("Discover Process Template");
// 	wf.startFlow(wfId, current, 'Insert');

	// Check the Maximum Running Templates and queue if exceeded.

	var maximumRunningTemplates = parseInt( gs.getProperty('x_153465_discovert.Maximum_Running_Templates'));
	var runningTemplates;
	if(maximumRunningTemplates > 0){
		// get the total count for the banner
		var ga = new GlideAggregate('x_153465_discovert_discover_routing_runtime');
		ga.addEncodedQuery('u_status=initialized^ORu_status=in_progress');
		ga.addAggregate("COUNT");
		ga.query();
		if(ga.next()){
			runningTemplates = ga.getAggregate("COUNT");
		}

	}
	// if the current template is run from a daily schedule, or the template was requested to be run asynchronously
	// or the maximum concurrent templates has been exceeded, then use event to queue run
	if(current.u_status == 'queued' || (maximumRunningTemplates > 0 && runningTemplates > maximumRunningTemplates)){
		// Queue Template
		// We understand that updating in an after insert is not best practice.
		// Howver we need to change the status to queued when too many templates are running
		// the setWorfklow flag is set to false so no other update events will fire
		// change to queued if greater than max running templates
		current.u_status = 'queued';
		current.setWorkflow(false);
		current.update();
		gs.eventQueue('x_153465_discovert.Start_Template', current, current.originator);
	} else {
		// Start Immediately
		var templaterunner = new Tasker_GenerateTaskFromTemplate().startTemplate(current);	
	}
})(current, previous);
